const theme = {
  mode: 'dark',
  log() { console.log(this.mode); },
};

theme.log();        // 'dark' — called as method
const fn = theme.log;
fn();               // undefined or error — lost this

const bound = theme.log.bind(theme);
bound();            // 'dark' — this restored

function describe(label) {
  return `${label}: ${this.mode}`;
}

const prefs = { mode: 'system' };

describe.call(prefs, 'Theme');   // 'Theme: system'
describe.apply(prefs, ['Theme']); // same result

class ThemeController {
  constructor() { this.mode = 'light'; }
  toggle() { this.mode = this.mode === 'light' ? 'dark' : 'light'; }
}

const ctrl = new ThemeController();
// Without bind, setTimeout loses this:
setTimeout(ctrl.toggle.bind(ctrl), 100);

export type ThemePreference = 'light' | 'dark' | 'system';
export type ResolvedTheme = 'light' | 'dark';

export interface ThemeContextValue {
  preference: ThemePreference;
  resolvedTheme: ResolvedTheme;
  setPreference: (preference: ThemePreference) => void;
}

import { createContext } from 'react';
import type { ThemeContextValue } from '../types/theme';

export const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: PropsWithChildren) {
  const [preference, setPreference] = useState<ThemePreference>(() => {
    return (localStorage.getItem('theme') as ThemePreference) ?? 'system';
  });

  const resolvedTheme = useResolvedTheme(preference);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', resolvedTheme);
    localStorage.setItem('theme', preference);
  }, [preference, resolvedTheme]);

  const value = useMemo(
    () => ({ preference, resolvedTheme, setPreference }),
    [preference, resolvedTheme],
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error('useTheme must be used within ThemeProvider');
  }
  return ctx;
}

function useResolvedTheme(preference: ThemePreference): ResolvedTheme {
  const getSystem = () =>
    window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';

  const [systemTheme, setSystemTheme] = useState<ResolvedTheme>(getSystem);

  useEffect(() => {
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    const handler = () => setSystemTheme(getSystem());
    mq.addEventListener('change', handler);
    return () => mq.removeEventListener('change', handler);
  }, []);

  if (preference === 'system') return systemTheme;
  return preference;
}
